// Прокси: собираем multipart/form-data из всех входящих binary-полей и шлём в
// table-merger Python-сервис. Возвращаем binary файл и его имя из заголовка
// Content-Disposition обратно в UI.
//
// URL сервиса автоопределяется: сначала пробуем localhost (n8n не в Docker —
// сразу попадаем), потом host.docker.internal (Docker Desktop резолвит это в
// IP хост-машины). Так workflow работает в обеих средах без правок:
//   - Дома: n8n в Docker → localhost даёт ECONNREFUSED → переходим на
//     host.docker.internal → доходим до Python-сервиса на хосте.
//   - В офисе: n8n напрямую → localhost работает с первой попытки.

// Каждый URL — объект с url и timeout. Первый URL — для быстрой проверки
// (короткий таймаут 3 сек), чтобы при отказе сразу падать на следующий.
// Используем 127.0.0.1 явно (а не localhost) — Node.js может резолвить
// localhost в IPv6 (::1) и зависать без ECONNREFUSED.
const MERGER_URLS = [
  { url: 'http://127.0.0.1:8082/merge',              timeout: 3000   },
  { url: 'http://host.docker.internal:8082/merge',   timeout: 180000 }
];

const input = $input.first();
const binary = input.binary || {};
const binaryKeys = Object.keys(binary);

if (binaryKeys.length === 0) {
  return [{ json: { success: false, error: 'Не загружено ни одного файла.' } }];
}

const boundary = '----WebKitFormBoundary' + Math.random().toString(16).slice(2) + Date.now().toString(16);
const chunks = [];

for (const key of binaryKeys) {
  const meta = binary[key];
  const buf = await this.helpers.getBinaryDataBuffer(0, key);
  const filename = (meta.fileName || (key + '.bin')).replace(/"/g, '');
  const contentType = meta.mimeType || 'application/octet-stream';

  chunks.push(Buffer.from('--' + boundary + '\r\n', 'utf8'));
  chunks.push(Buffer.from(
    'Content-Disposition: form-data; name="files"; filename="' + filename + '"\r\n',
    'utf8'
  ));
  chunks.push(Buffer.from('Content-Type: ' + contentType + '\r\n\r\n', 'utf8'));
  chunks.push(buf);
  chunks.push(Buffer.from('\r\n', 'utf8'));
}
chunks.push(Buffer.from('--' + boundary + '--\r\n', 'utf8'));
const body = Buffer.concat(chunks);

// Network errors — при них пробуем следующий URL. Включает таймаут, потому что
// внутри Docker контейнера попытка достучаться до loopback может зависать без
// ECONNREFUSED (см. IPv6 vs IPv4 проблему). Любая другая ошибка (4xx/5xx от
// сервиса) означает что сервис ДОСТУПЕН и пробрасывается пользователю.
const NET_ERR_CODES = ['ECONNREFUSED', 'ENOTFOUND', 'EHOSTUNREACH', 'EAI_AGAIN', 'ETIMEDOUT', 'ECONNABORTED', 'ECONNRESET'];
const isNetworkErr = (e) => {
  const code = (e.cause && e.cause.code) || e.code || '';
  if (NET_ERR_CODES.includes(code)) return true;
  const msg = String(e.message || '').toLowerCase();
  return msg.includes('timeout') || msg.includes('econnrefused') || msg.includes('enotfound') || msg.includes('connect');
};

let response = null;
let nonNetworkErr = null;
for (const entry of MERGER_URLS) {
  try {
    response = await this.helpers.httpRequest({
      method: 'POST',
      url: entry.url,
      body,
      headers: {
        'Content-Type': 'multipart/form-data; boundary=' + boundary,
        'Content-Length': String(body.length)
      },
      encoding: 'arraybuffer',
      returnFullResponse: true,
      timeout: entry.timeout
    });
    break;  // успех — прекращаем перебор
  } catch (e) {
    if (isNetworkErr(e)) {
      // сервис недоступен на этом URL — пробуем следующий
      continue;
    }
    // ошибка от сервиса (4xx/5xx) — на этом останавливаемся
    nonNetworkErr = e;
    break;
  }
}

if (nonNetworkErr) {
  let errMsg = nonNetworkErr.message || 'Ошибка вызова table-merger';
  if (nonNetworkErr.response && nonNetworkErr.response.body) {
    try {
      const txt = Buffer.from(nonNetworkErr.response.body).toString('utf8');
      const parsed = JSON.parse(txt);
      if (parsed && parsed.detail) errMsg = parsed.detail;
      else errMsg = txt.slice(0, 500);
    } catch (_) {
      errMsg = Buffer.from(nonNetworkErr.response.body).toString('utf8').slice(0, 500);
    }
  }
  return [{ json: { success: false, error: errMsg } }];
}

if (!response) {
  return [{ json: { success: false, error: 'table-merger сервис не запущен. Запусти start.bat на хост-машине (порт 8082).' } }];
}

// Парсим Content-Disposition: filename="merged.docx"; filename*=UTF-8''merged.docx
const headers = response.headers || {};
const cd = headers['content-disposition'] || headers['Content-Disposition'] || '';
let outFilename = 'merged.bin';
let m = cd.match(/filename\*=UTF-8''([^;]+)/i);
if (m) {
  try { outFilename = decodeURIComponent(m[1]); } catch (_) { outFilename = m[1]; }
} else {
  m = cd.match(/filename="?([^";]+)"?/i);
  if (m) outFilename = m[1];
}
const outMime = headers['content-type'] || headers['Content-Type'] || 'application/octet-stream';

const outBuffer = Buffer.from(response.body);
const binaryData = await this.helpers.prepareBinaryData(outBuffer, outFilename, outMime);

return [{
  json: { success: true, filename: outFilename, size: outBuffer.length, files: binaryKeys.length },
  binary: { data: binaryData }
}];
